    previous_state = controller->state;

    /* Check for stale sensor data (>1000ms since last valid reading) */
    uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
    bool is_stale = (controller->has_valid_sensor && (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS));

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        /* Save old temperature before updating to check if rising */
        int old_temperature_c = controller->last_temperature_c;
        bool had_valid_sensor_before = controller->has_valid_sensor;

        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Implement thermal control policy */
        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* TEMP < 47: turn heater ON */
            controller_set_heating(controller);
        } else if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* TEMP > 52: turn heater OFF (SAFE_OFF) */
            controller_set_safe_off(controller);
        } else if (input.temperature_c >= CONTROLLER_TEMP_LOW_THRESHOLD &&
                   input.temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* 47 <= TEMP < 50: hold previous safe actuator state */
            controller_set_holding(controller, previous_heater_on);
        } else if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD &&
                   input.temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* 50 <= TEMP <= 52: check if temperature is rising */
            bool temp_rising = had_valid_sensor_before &&
                               (input.temperature_c > old_temperature_c);
            if (temp_rising) {
                /* Temperature rising: turn heater OFF early, treat as HOLDING */
                controller_set_holding(controller, false);
            } else {
                /* Not rising: hold previous safe actuator state */
                controller_set_holding(controller, previous_heater_on);
            }
        }
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        /* On explicit sensor timeout or malformed input: turn heater OFF */
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        output.timed_out = (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT);
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No new input - check for stale data */
        if (is_stale) {
            /* Stale sensor data (>1000ms): turn heater OFF */
            controller_set_safe_off(controller);
            output.timed_out = true;
        }
        break;
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}
